  { nom: "Optimhome", slug: "optimhome", domaine: "optimhome.com", patterns: ["optimhome", "optim home", "conseiller optimhome"] },
  { nom: "BSK Immobilier", slug: "bsk", domaine: "bsk-immobilier.com", patterns: ["bsk immobilier", "bsk-immobilier", "conseiller bsk"] },
