  { nom: "Proprietes-Privees", slug: "proprietes-privees", domaine: "proprietes-privees.com", patterns: ["proprietes privees", "propriétés privées", "proprietes-privees"] },
  { nom: "Keller Williams", slug: "kw", domaine: "kwfrance.com", patterns: ["keller williams", "kw france", "agent kw"] },
