  { nom: "Arthurimmo", slug: "arthurimmo", domaine: "arthurimmo.com", patterns: ["arthurimmo", "arthur immo"] },
  { nom: "Ledil Immobilier", slug: "ledil", domaine: "ledil.immo", patterns: ["ledil", "le dil", "ledil immobilier"] },
