  { nom: "Cimm Immobilier", slug: "cimm", domaine: "cimm.com", patterns: ["cimm immobilier", "cimm"] },
  { nom: "Nestenn", slug: "nestenn", domaine: "nestenn.com", patterns: ["nestenn"] }
];

const MOTS_A_SUPPRIMER = [
  "mandataire", "mandataires", "agent", "agents", "conseiller", "conseillers",
  "consultant", "consultants", "négociateur", "négociateurs", "commercial", "commerciaux",
  "expert", "experts", "spécialiste", "spécialistes",
  "immobilier", "immobilière", "immobiliers", "immo", "real estate",
  "transaction", "transactions", "vente", "ventes", "location", "locations",
  "gestion", "patrimoine", "investissement",
  "indépendant", "indépendante", "indépendants", "freelance",
  "professionnel", "professionnelle", "professionnels"
];

const VILLES_FRANCAISES = [
  "paris", "marseille", "lyon", "toulouse", "nice", "nantes", "strasbourg",
  "montpellier", "bordeaux", "lille", "rennes", "reims", "le havre", "saint-étienne",
  "toulon", "grenoble", "dijon", "angers", "nîmes", "villeurbanne", "clermont-ferrand",
  "le mans", "aix-en-provence", "brest", "tours", "amiens", "limoges", "annecy",
  "perpignan", "boulogne-billancourt", "metz", "besançon", "orléans", "rouen",
  "mulhouse", "caen", "nancy", "saint-denis", "argenteuil", "montreuil"
];

function normaliser(str) {
  if (!str) return "";
  return str.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/œ/g, "oe").replace(/æ/g, "ae").trim();
}

function supprimerEmojis(str) {
  if (!str) return "";
  return str.replace(/[\u{1F600}-\u{1F64F}]|[\u{1F300}-\u{1F5FF}]|[\u{1F680}-\u{1F6FF}]|[\u{1F1E0}-\u{1F1FF}]|[\u{2600}-\u{26FF}]|[\u{2700}-\u{27BF}]/gu, "").trim();
}

function detecterReseau(titre, description = "", website = "") {
  const texteComplet = normaliser(`${titre} ${description} ${website}`);
  for (const reseau of RESEAUX_MANDATAIRES) {
    for (const pattern of reseau.patterns) {
      if (texteComplet.includes(normaliser(pattern))) {
        return { detecte: true, nom: reseau.nom, slug: reseau.slug, domaine: reseau.domaine };
      }
    }
  }
  return { detecte: false, nom: null, slug: null, domaine: null };
}

function extraireIdentite(titreOriginal, villeGoogleMaps = "") {
  let titre = supprimerEmojis(titreOriginal || "");
  titre = titre.replace(/[|•·●○◦▪▫►◄★☆✓✔✗✘→←↑↓↔↕]/g, " ").replace(/[-–—]{2,}/g, " ").replace(/[()[\]{}]/g, " ");

  let titreNormalise = normaliser(titre);
  for (const mot of MOTS_A_SUPPRIMER) {
    const regex = new RegExp(`\\b${normaliser(mot)}\\b`, "gi");
    titreNormalise = titreNormalise.replace(regex, " ");
    titre = titre.replace(new RegExp(`\\b${mot}\\b`, "gi"), " ");
  }

  if (villeGoogleMaps) titre = titre.replace(new RegExp(`\\b${villeGoogleMaps}\\b`, "gi"), " ");
  for (const ville of VILLES_FRANCAISES) titre = titre.replace(new RegExp(`\\b${ville}\\b`, "gi"), " ");

  titre = titre.replace(/\b\d{5}\b/g, " ").replace(/\b\d{2,4}\b/g, " ").replace(/\s+/g, " ").trim();

  const mots = titre.split(" ").filter(m => m.length >= 2);
  let prenom = "", nom = "";

  if (mots.length >= 2) {
    prenom = mots[0].charAt(0).toUpperCase() + mots[0].slice(1).toLowerCase();
    nom = mots.slice(1).map(w => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase()).join(" ");
  } else if (mots.length === 1) {
    prenom = mots[0].charAt(0).toUpperCase() + mots[0].slice(1).toLowerCase();
  }

  let confiance = 0;
  if (prenom && prenom.length >= 2) confiance += 30;
  if (nom && nom.length >= 2) confiance += 30;
  if (prenom && /^[A-Za-zÀ-ÿ-]+$/.test(prenom) && prenom.length <= 15) confiance += 20;
  if (nom && /^[A-Za-zÀ-ÿ-\s]+$/.test(nom) && nom.length <= 25) confiance += 20;

  return { prenom, nom, nom_complet: [prenom, nom].filter(Boolean).join(" "), titre_nettoye: titre, confiance: Math.min(confiance, 100) };
}

function genererEmail(prenom, nom, reseau) {
  if (!reseau.detecte || !reseau.domaine || !prenom || !nom) {
    return { email: null, methode: "non_generable", confiance: 0 };
  }
  const prenomEmail = normaliser(prenom).replace(/\s+/g, "").replace(/-/g, "");
  const nomEmail = normaliser(nom).replace(/\s+/g, "").replace(/-/g, "");
  return { email: `${prenomEmail}.${nomEmail}@${reseau.domaine}`, methode: "pattern_matching", confiance: 75 };
}

function scorerLead(item, identite, reseau, emailGenere) {
  let score = 0;
  if (reseau.detecte) score += 25;
  if (emailGenere.email) score += 25;
  if (item.phone || item.phoneUnformatted) score += 15;
  if (item.website) score += 10;
  score += Math.floor(identite.confiance * 0.15);
  if (item.reviewsCount) score += Math.min(Math.floor(item.reviewsCount / 5), 10);
  if (item.totalScore && item.totalScore >= 4) score += 5;
  return { score: Math.min(score, 100), niveau: score >= 70 ? "A" : score >= 50 ? "B" : score >= 30 ? "C" : "D" };
}

function extraireDepartement(codePostal) {
  if (!codePostal) return "";
  const cp = codePostal.toString().padStart(5, "0");
  if (cp.startsWith("20")) {
    const num = parseInt(cp.substring(0, 3));
    if (num >= 200 && num <= 201) return "2A";
    if (num >= 202 && num <= 209) return "2B";
  }
  if (cp.startsWith("97") || cp.startsWith("98")) return cp.substring(0, 3);
  return cp.substring(0, 2);
}

// TRAITEMENT PRINCIPAL
const items = $input.all();
const resultats = [];

for (const item of items) {
  try {
    const data = item.json;
    const reseau = detecterReseau(data.title, data.description || "", data.website || "");
    const identite = extraireIdentite(data.title, data.city || data.neighborhood || "");
    const emailGenere = genererEmail(identite.prenom, identite.nom, reseau);
    const qualite = scorerLead(data, identite, reseau, emailGenere);

    if (emailGenere.email || data.phone || data.phoneUnformatted || reseau.detecte) {
      resultats.push({
        json: {
          prenom: identite.prenom,
          nom: identite.nom,
          nom_complet: identite.nom_complet,
          email: emailGenere.email,
          email_confiance: emailGenere.confiance,
          telephone: data.phone || data.phoneUnformatted || null,
          reseau_nom: reseau.nom,
          ville: data.city || data.neighborhood || "",
          adresse: data.address || "",
          departement: extraireDepartement(data.postalCode),
          code_postal: data.postalCode || "",
          titre_original: data.title,
          note_google: data.totalScore || null,
          nb_avis: data.reviewsCount || 0,
          website: data.website || "",
          url_google: data.url || "",
          score_qualite: qualite.score,
          niveau_qualite: qualite.niveau,
          date_scraping: new Date().toISOString(),
          statut: "NOUVEAU"
        }
      });
    }
  } catch (error) {
    console.error(`Erreur enrichissement: ${error.message}`);
  }
}

return resultats;

const items = $input.all();
const data = items[0].json.data || [];

const stats = {
  total_leads: data.length,
  leads_A: data.filter(d => d.niveau_qualite === 'A').length,
  leads_B: data.filter(d => d.niveau_qualite === 'B').length,
  leads_C: data.filter(d => d.niveau_qualite === 'C').length,
  avec_email: data.filter(d => d.email).length,
  avec_telephone: data.filter(d => d.telephone).length,
  reseaux: [...new Set(data.filter(d => d.reseau_nom).map(d => d.reseau_nom))],
  villes: [...new Set(data.map(d => d.ville).filter(Boolean))],
  date_run: new Date().toISOString()
};

return [{ json: stats }];
